    chunk: &crate::types::ScoredCodeChunk,
    query_lower: &str,
    terms: &[String],
    codeish: bool,
) -> f32 {
    let path = chunk.file_path.to_lowercase();
    let name = chunk.name.clone().unwrap_or_default().to_lowercase();
    let ctx = chunk
        .context_path
        .clone()
        .unwrap_or_default()
        .to_lowercase();
    let content = chunk.content.to_lowercase();

    let mut raw = 0.0f32;
    let mut matched_terms = 0usize;
    let mut strong_hit = false;

    if query_lower.len() >= 4
        && (path.contains(query_lower) || name.contains(query_lower) || ctx.contains(query_lower))
    {
        raw += 1.8;
        strong_hit = true;
    }

    for term in terms {
        if term.len() < 2 {
            continue;
        }
        let in_name = !name.is_empty() && name.contains(term);
        let in_path = path.contains(term);
        let in_ctx = !ctx.is_empty() && ctx.contains(term);
        let in_content = content.contains(term);

        if in_name {
            raw += 0.7;
            matched_terms += 1;
            strong_hit = true;
        } else if in_path {
            raw += 0.55;
            matched_terms += 1;
            strong_hit = true;
        } else if in_ctx {
            raw += 0.45;
            matched_terms += 1;
        } else if in_content {
            raw += 0.2;
            matched_terms += 1;
        }
    }

    if !terms.is_empty() {
        raw += 0.8 * (matched_terms as f32 / terms.len() as f32);
    }

    if codeish && strong_hit {
        raw += 0.8;
    }

    // Penalize very short generic chunks unless they have strong lexical evidence.
    if chunk.content.len() < 96 && !strong_hit {
        raw -= 0.6;
    }

    raw.clamp(0.0, 4.0) / 4.0
}","context_path":null,"end_line":252,"exact_score":0.0,"file_path":"/var/folders/mx/tffz_j1d5lg_twyfntz97yr00000gp/T/task-9-code-retrieval-project-wl_k3r60/task-9-code-retrieval-fixture/src/server/logic/code/search.rs","id":"2617fde26b5c54b1f211","language":"rust","lexical_score":0.34166666865348816,"name":null,"ppr_score":0.05128205567598343,"rrf_score":0.01348305493593216,"score":0.01621638797223568,"start_line":186,"vector_score":0.8496565818786621},{"bm25_score":12.821795463562012,"chunk_type":"function","content":"fn code_search_contract_json(
