            has_filters,
            codeish_query,
            vector_weight,
            bm25_weight,
            ppr_weight,
        );
        timing.count("limit", limit);
        timing.count("fetch_limit", fetch_limit);
        timing.count("has_filters", has_filters);
        timing.count("query_terms_len", query_terms.len());
        timing.count("codeish_query", codeish_query);
    }

