        for i in 0..n {
            new_scores[i] += damping * dangling_sum * personalization[i];
            new_scores[i] += (1.0 - damping) * personalization[i];
        }

        let diff: f32 = scores
            .iter()
            .zip(new_scores.iter())
            .map(|(a, b)| (a - b).abs())
            .sum();

        scores = new_scores;

        if diff < tolerance {
            break;
        }
    }

